import emailjs from '@emailjs/browser';
import { useRef } from 'react';

const Contact = () => {
  const form = useRef();

  const sendEmail = (e) => {
    e.preventDefault();

    emailjs.sendForm(
      'YOUR_SERVICE_ID',
      'YOUR_TEMPLATE_ID',
      form.current,
      'YOUR_PUBLIC_KEY'
    )
    .then((result) => {
      console.log('Email sent successfully:', result.text);
      alert('Message Sent!');
      e.target.reset();
    }, (error) => {
      console.error('Error sending email:', error.text);
      alert('Failed to send message, please try again later.');
    });
  };

  return (
    <section id="contact" style={{ textAlign: "center", padding: "3rem 2rem" }}>
      <h2>Get In Touch</h2>
      <form ref={form} onSubmit={sendEmail} style={{ display: "flex", flexDirection: "column", gap: "1rem", maxWidth: "400px", margin: "auto" }}>
        <input type="text" name="from_name" placeholder="Your name" required style={inputStyle} />
        <input type="email" name="from_email" placeholder="Your email" required style={inputStyle} />
        <textarea name="message" placeholder="Your message..." rows="5" required style={textareaStyle}></textarea>
        <button type="submit" style={submitButtonStyle}>Send Message</button>
      </form>
    </section>
  );
};
